1	/**
2	 * WhatsApp bot adapter for GAIA.
3	 *
4	 * Extends {@link BaseBotAdapter} to wire unified commands and events
5	 * to the Kapso webhook framework. Handles WhatsApp-specific concerns:
6	 *
7	 * - **Webhook server** via Hono + @hono/node-server
8	 * - **Signature verification** via HMAC-SHA256 on raw body
9	 * - **Text commands** matched by prefix (e.g. "/gaia ...")
10	 * - **Rich messages** rendered as WhatsApp markdown (*bold*, _italic_)
11	 * - **No streaming** — full response sent once complete (streaming: false)
12	 * - **No message editing** — WhatsApp API does not support edits
13	 * - **Typing indicator** fired once per message (Meta hard-caps bubble at 25s)
14	 *
15	 * @module
16	 */
17	
18	import {
19	  BaseBotAdapter,
20	  type BotCommand,
21	  convertToWhatsAppMarkdown,
22	  createBotLogger,
23	  handleStreamingChat,
24	  hashLogIdentifier,
25	  type PlatformName,
26	  parseTextArgs,
27	  type RichMessage,
28	  type RichMessageTarget,
29	  richMessageToMarkdown,
30	  type SentMessage,
31	  STREAMING_DEFAULTS,
32	  sanitizeErrorForLog,
33	} from "@gaia/shared";
34	import { WhatsAppClient } from "@kapso/whatsapp-cloud-api";
35	import {
36	  extractTextBody,
37	  extractWaId,
38	  type KapsoMessageBatch,
39	  type KapsoMessageEvent,
40	  verifyKapsoSignature,
41	} from "./webhook";
42	
43	// ─── WhatsApp-specific config ─────────────────────────────────────────────────
44	
45	interface WhatsAppConfig {
46	  kapsoApiKey: string;
47	  kapsoPhoneNumberId: string;
48	  kapsoWebhookSecret: string;
49	}
50	
51	function loadWhatsAppConfig(): WhatsAppConfig {
52	  const kapsoApiKey = process.env.KAPSO_API_KEY;
53	  const kapsoPhoneNumberId = process.env.KAPSO_PHONE_NUMBER_ID;
54	  const kapsoWebhookSecret = process.env.KAPSO_WEBHOOK_SECRET;
55	
56	  if (!kapsoApiKey) throw new Error("KAPSO_API_KEY is required");
57	  if (!kapsoPhoneNumberId) throw new Error("KAPSO_PHONE_NUMBER_ID is required");
58	  if (!kapsoWebhookSecret) throw new Error("KAPSO_WEBHOOK_SECRET is required");
59	
60	  return { kapsoApiKey, kapsoPhoneNumberId, kapsoWebhookSecret };
61	}
62	
63	// ─── WhatsApp Adapter ─────────────────────────────────────────────────────────
64	
65	export class WhatsAppAdapter extends BaseBotAdapter {
66	  readonly platform: PlatformName = "whatsapp";
67	  protected readonly defaultServerPort = 3203;
68	
69	  private waClient: WhatsAppClient | null = null;
70	  private waConfig: WhatsAppConfig | null = null;
71	
72	  /** Tracks users who have already received a welcome message this process. */
73	  private readonly welcomeSent = new Set<string>();
74	  /**
75	   * Tracks users whose platform_links status has been confirmed as linked this
76	   * process. Avoids a backend round-trip on every first-seen message after restart.
77	   */
78	  private readonly linkedUsers = new Set<string>();
79	  /**
80	   * Per-user message processing queue. Serializes handleIncomingMessage calls for
81	   * the same waId so rapid messages or batched webhook deliveries never run in
82	   * parallel — eliminates overlapping typing states and interleaved replies.
83	   */
84	  private readonly messageQueues = new Map<string, Promise<void>>();
85	  private readonly adapterLogger = createBotLogger("whatsapp", "adapter");
86	
87	  private get whatsAppClient(): WhatsAppClient {
88	    if (!this.waClient) {
89	      throw new Error("WhatsApp client not initialized — call boot() first");
90	    }
91	    return this.waClient;
92	  }
93	
94	  private get whatsAppConfig(): WhatsAppConfig {
95	    if (!this.waConfig) {
96	      throw new Error("WhatsApp config not initialized — call boot() first");
97	    }
98	    return this.waConfig;
99	  }
100	
101	  // ---------------------------------------------------------------------------
102	  // Lifecycle
103	  // ---------------------------------------------------------------------------
104	
105	  /** Initializes the Kapso WhatsApp client using environment variables. */
106	  protected async initialize(): Promise<void> {
107	    this.waConfig = loadWhatsAppConfig();
108	    this.waClient = new WhatsAppClient({
109	      baseUrl: "https://api.kapso.ai/meta/whatsapp",
110	      kapsoApiKey: this.waConfig.kapsoApiKey,
111	    });
112	    this.adapterLogger.info("client_initialized", {
113	      phone_number_id: this.waConfig.kapsoPhoneNumberId,
114	    });
115	  }
116	
117	  /** WhatsApp has no platform-level command registration step. */
118	  protected async registerCommands(_commands: BotCommand[]): Promise<void> {
119	    this.adapterLogger.info("commands_registered");
120	  }
121	
122	  /**
123	   * Mounts the Kapso webhook handler on the shared base server.
124	   *
125	   * The base server already provides `GET /health`. This method adds:
126	   *
127	   * - POST /webhook → verifies Kapso HMAC signature, dispatches message
128	   */
129	  protected async registerEvents(): Promise<void> {
130	    this.botServer.app.post("/webhook", async (c) => {
131	      const rawBody = await c.req.text();
132	      const signature = c.req.header("x-webhook-signature") ?? null;
133	
134	      if (
135	        !verifyKapsoSignature(
136	          rawBody,
137	          signature,
138	          this.whatsAppConfig.kapsoWebhookSecret,
139	        )
140	      ) {
141	        return c.json({ error: "Invalid signature" }, 401);
142	      }
143	
144	      // Event type is in the header for Kapso webhooks, not in the body
145	      const eventType = c.req.header("x-webhook-event") ?? null;
146	      if (eventType !== "whatsapp.message.received") {
147	        this.adapterLogger.debug("webhook_event_ignored", {
148	          event_type: eventType,
149	        });
150	        return c.json({ status: "ignored" });
151	      }
152	
153	      let body: unknown;
154	      try {
155	        body = JSON.parse(rawBody);
156	      } catch {
157	        return c.json({ error: "Invalid JSON" }, 400);
158	      }
159	
160	      // Batched delivery wraps events in { batch: true, data: [...] }
161	      const isBatch = c.req.header("x-webhook-batch") === "true";
162	      const events: KapsoMessageEvent[] = isBatch
163	        ? (body as KapsoMessageBatch).data
164	        : [body as KapsoMessageEvent];
165	
166	      for (const event of events) {
167	        const waId = extractWaId(event);
168	        const waIdHash = hashLogIdentifier(waId);
169	        const text = extractTextBody(event);
170	        this.adapterLogger.info("webhook_message_received", {
171	          wa_hash: waIdHash,
172	          message_type: event.message.type,
173	          has_text: Boolean(text),
174	        });
175	        if (text) {
176	          // Enqueue per user — webhook returns 200 immediately while processing
177	          // is serialized: messages from the same user run one at a time, in order.
178	          const msgId = event.message.id;
179	          this.enqueueForUser(waId, () =>
180	            this.handleIncomingMessage(waId, text, msgId).catch((err) =>
181	              this.adapterLogger.error("incoming_message_processing_failed", {
182	                wa_hash: waIdHash,
183	                message_id: msgId,
184	                ...sanitizeErrorForLog(err),
185	              }),
186	            ),
187	          );
188	        } else if (event.message.type !== "text") {
189	          // Non-text message (image, audio, video, document, etc.)
190	          this.handleUnsupportedMedia(waId, event.message.type).catch((err) =>
191	            this.adapterLogger.error("unsupported_media_handling_failed", {
192	              wa_hash: waIdHash,
193	              message_type: event.message.type,
194	              ...sanitizeErrorForLog(err),
195	            }),
196	          );
197	        }
198	      }
199	
200	      return c.json({ status: "ok" });
201	    });
202	  }
203	
204	  /** Nothing additional to start — base server is started by BaseBotAdapter.boot(). */
205	  protected async start(): Promise<void> {
206	    this.adapterLogger.info("bot_started");
207	  }
208	
209	  /** Nothing additional to stop — base server is stopped by BaseBotAdapter.shutdown(). */
210	  protected stop(): Promise<void> {
211	    return Promise.resolve();
212	  }
213	
214	  // ---------------------------------------------------------------------------
215	  // Message handling
216	  // ---------------------------------------------------------------------------
217	
218	  /**
219	   * Serializes message processing per user. Chains the new task onto the tail of
220	   * the existing promise for this waId so messages are always handled one at a
221	   * time, in order. Cleans up the map entry once the task settles.
222	   */
223	  private enqueueForUser(waId: string, fn: () => Promise<void>): void {
224	    const previous = this.messageQueues.get(waId) ?? Promise.resolve();
225	    const task = previous
226	      .catch(() => undefined) // previous failure must not block the queue
227	      .then(() => fn());
228	    this.messageQueues.set(waId, task);
229	    task.then(
230	      () => {
231	        if (this.messageQueues.get(waId) === task)
232	          this.messageQueues.delete(waId);
233	      },
234	      () => {
235	        if (this.messageQueues.get(waId) === task)
236	          this.messageQueues.delete(waId);
237	      },
238	    );
239	  }
240	
241	  /**
242	   * Dispatches an incoming WhatsApp message to the appropriate handler.
243	   *
244	   * Shows a typing indicator immediately (mark-as-read + typing via Kapso API),
245	   * then routes:
246	   * - Messages starting with "/" are parsed as commands
247	   * - `/gaia <text>` invokes streaming chat
248	   * - Other `/command` messages invoke the unified command dispatcher
249	   * - Plain text messages are treated as implicit `/gaia` chat
250	   */
251	  private async handleIncomingMessage(
252	    waId: string,
253	    text: string,
254	    messageId: string,
255	  ): Promise<void> {
256	    const waIdHash = hashLogIdentifier(waId);
257	    this.adapterLogger.info("incoming_message_started", {
258	      wa_hash: waIdHash,
259	      message_id: messageId,
260	      text_length: text.length,
261	      is_command: text.startsWith("/"),
262	    });
263	
264	    const showTyping = () =>
265	      this.whatsAppClient.messages
266	        .markRead({
267	          phoneNumberId: this.whatsAppConfig.kapsoPhoneNumberId,
268	          messageId,
269	          typingIndicator: { type: "text" },
270	        })
271	        .catch((err: unknown) =>
272	          this.adapterLogger.error("typing_indicator_failed", {
273	            wa_hash: waIdHash,
274	            message_id: messageId,
275	            ...sanitizeErrorForLog(err),
276	          }),
277	        );
278	
279	    showTyping();
280	    const typingInterval = setInterval(showTyping, 20_000);
281	    const clearTyping = () => clearInterval(typingInterval);
282	
283	    try {
284	      if (!this.welcomeSent.has(waId)) {
285	        this.welcomeSent.add(waId);
286	
287	        let isLinked = this.linkedUsers.has(waId);
288	        if (!isLinked) {
289	          try {
290	            const timeoutMs = 2_000;
291	            const statusPromise = this.gaia.checkAuthStatus("whatsapp", waId);
292	            const timeoutPromise = new Promise<never>((_, reject) =>
293	              setTimeout(
294	                () => reject(new Error("auth_check_timeout")),
295	                timeoutMs,
296	              ),
297	            );
298	            const status = await Promise.race([statusPromise, timeoutPromise]);
299	            isLinked = status.authenticated;
300	            if (isLinked) this.linkedUsers.add(waId);
301	          } catch (err) {
302	            this.adapterLogger.warn("welcome_auth_check_failed", {
303	              wa_hash: waIdHash,
304	              ...sanitizeErrorForLog(err),
305	            });
306	          }
307	        }
308	
309	        if (!isLinked) {
310	          await this.sendWelcome(waId);
311	          showTyping();
312	        }
313	      }
314	
315	      const target = this.createWaTarget(waId, messageId);
316	
317	      if (text.startsWith("/")) {
318	        const withoutSlash = text.slice(1);
319	        const spaceIndex = withoutSlash.indexOf(" ");
320	        const commandName = (
321	          spaceIndex === -1 ? withoutSlash : withoutSlash.slice(0, spaceIndex)
322	        ).toLowerCase();
323	        const rest =
324	          spaceIndex === -1 ? "" : withoutSlash.slice(spaceIndex + 1).trim();
325	
326	        if (commandName === "gaia") {
327	          if (!rest) {
328	            await this.sendWhatsAppText(waId, "Usage: /gaia <your message>");
329	            return;
330	          }
331	          await this.handleStreamingMessage(waId, rest);
332	          return;
333	        }
334	
335	        const args: Record<string, string | number | boolean | undefined> = {};
336	        if (commandName === "todo" || commandName === "workflow") {
337	          const parsed = parseTextArgs(rest);
338	          args.subcommand = parsed.subcommand;
339	        }
340	
341	        await this.dispatchCommand(
342	          commandName,
343	          target,
344	          args,
345	          rest || undefined,
346	        );
347	        return;
348	      }
349	
350	      await this.handleStreamingMessage(waId, text);
351	    } finally {
352	      clearTyping();
353	    }
354	  }
355	
356	  /**
357	   * Sends the user's message to the GAIA streaming endpoint.
358	   *
359	   * WhatsApp streaming is disabled (STREAMING_DEFAULTS.whatsapp.streaming = false),
360	   * so the full response is accumulated and sent as a single message.
361	   * The typing indicator was already fired once before this is called and will
362	   * auto-dismiss when the reply is sent (Meta's hard 25s ceiling).
363	   */
364	  private async handleStreamingMessage(
365	    waId: string,
366	    text: string,
367	  ): Promise<void> {
368	    if (!text.trim()) {
369	      await this.sendWhatsAppText(
370	        waId,
371	        "Hi! Send me a message and I'll help you. Type /help for available commands.",
372	      );
373	      return;
374	    }
375	
376	    let lastEditFn: ((t: string) => Promise<void>) | null = null;
377	    let finalMessageSent = false;
378	
379	    try {
380	      await handleStreamingChat(
381	        this.gaia,
382	        {
383	          message: text,
384	          platform: "whatsapp",
385	          platformUserId: waId,
386	          channelId: waId,
387	        },
388	        // editMessage: no placeholder to edit — send as new message on first call
389	        async (updatedText: string) => {
390	          if (finalMessageSent) {
391	            // WhatsApp has no edit API — edit() sends a new message.
392	            // Guard against sending multiple new messages if streaming is
393	            // ever re-enabled or editMessage is called more than once.
394	            return;
395	          }
396	          finalMessageSent = true;
397	          const formatted = convertToWhatsAppMarkdown(updatedText);
398	          if (lastEditFn) {
399	            await lastEditFn(formatted);
400	          } else {
401	            const sent = await this.sendWhatsAppText(waId, formatted);
402	            lastEditFn = sent.edit;
403	          }
404	        },
405	        // sendNewMessage: send a new message and return its edit function
406	        async (newText: string) => {
407	          const sent = await this.sendWhatsAppText(
408	            waId,
409	            convertToWhatsAppMarkdown(newText),
410	          );
411	          lastEditFn = sent.edit;
412	          return sent.edit;
413	        },
414	        // onAuthError
415	        async (authUrl: string) => {
416	          await this.sendWhatsAppText(
417	            waId,
418	            `To use GAIA on WhatsApp, link your account first:\n${authUrl}`,
419	          );
420	        },
421	        // onGenericError
422	        async (errMsg: string) => {
423	          await this.sendWhatsAppText(waId, errMsg);
424	        },
425	        STREAMING_DEFAULTS.whatsapp,
426	        this.analytics,
427	      );
428	    } catch (err) {
429	      this.adapterLogger.error("streaming_failed", {
430	        wa_hash: hashLogIdentifier(waId),
431	        ...sanitizeErrorForLog(err),
432	      });
433	      try {
434	        await this.sendWhatsAppText(
435	          waId,
436	          "An error occurred. Please try again.",
437	        );
438	      } catch (sendErr) {
439	        this.adapterLogger.error("streaming_error_message_send_failed", {
440	          wa_hash: hashLogIdentifier(waId),
441	          ...sanitizeErrorForLog(sendErr),
442	        });
443	      }
444	    }
445	  }
446	
447	  // ---------------------------------------------------------------------------
448	  // Welcome message
449	  // ---------------------------------------------------------------------------
450	
451	  /**
452	   * Sends a welcome message to a first-time WhatsApp user.
453	   *
454	   * Adapted from Discord's DM welcome embed — rendered as WhatsApp markdown
455	   * since WhatsApp has no native embed/button support.
456	   *
457	   * Gated by platform_links check via `gaia.checkAuthStatus` (2s timeout) — linked
458	   * users skip the welcome entirely and are cached in {@link linkedUsers} for the
459	   * process lifetime. Unlinked users receive it once per process restart at most,
460	   * tracked via {@link welcomeSent}.
461	   */
462	  private async sendWelcome(waId: string): Promise<void> {
463	    const text =
464	      `*Hey, I'm GAIA* 👋\n\n` +
465	      `Your personal AI — built to think ahead, remember everything, and get things done with you.\n\n` +
466	      `Here's what I can do right on WhatsApp:\n\n` +
467	      `*💬 Chat*\nJust type anything. Ask questions, brainstorm, think out loud.\n\n` +
468	      `*✅ Todos*\nUse /todo add to capture tasks.\n\n` +
469	      `*⚡ Workflows*\nRun automations with /workflow. Delegate entire projects.\n\n` +
470	      `*🔗 Link your account*\nUse /auth to connect your GAIA account for memory and personalization.\n\n` +
471	      `_Visit heygaia.io or read the docs at docs.heygaia.io_`;
472	
473	    try {
474	      await this.sendWhatsAppText(waId, text);
475	    } catch {
476	      // If we can't send the welcome, continue silently (match Discord behavior)
477	    }
478	  }
479	
480	  // ---------------------------------------------------------------------------
481	  // Unsupported media handler
482	  // ---------------------------------------------------------------------------
483	
484	  /**
485	   * Replies to non-text messages (images, audio, video, documents) with a
486	   * helpful message explaining that only text is currently supported.
487	   */
488	  private async handleUnsupportedMedia(
489	    waId: string,
490	    messageType: string,
491	  ): Promise<void> {
492	    const typeLabelMap: Record<string, string> = {
493	      image: "images",
494	      audio: "audio messages",
495	      voice: "audio messages",
496	      video: "videos",
497	      document: "documents",
498	    };
499	    const typeLabel = typeLabelMap[messageType] ?? `${messageType} messages`;
500	
501	    await this.sendWhatsAppText(
502	      waId,
503	      `I can't process ${typeLabel} yet — please send your message as text. Type /help for available commands.`,
504	    );
505	  }
506	
507	  // ---------------------------------------------------------------------------
508	  // Message target factory
509	  // ---------------------------------------------------------------------------
510	
511	  /**
512	   * Creates a {@link RichMessageTarget} for sending messages to a WhatsApp user.
513	   *
514	   * - `send` / `sendEphemeral` send a text message (no ephemeral concept in WhatsApp)
515	   * - `sendRich` renders {@link RichMessage} as WhatsApp markdown
516	   * - `edit` sends a NEW message (WhatsApp does not support editing)
517	   * - `startTyping` is a no-op — typing is already managed by `handleIncomingMessage`
518	   */
519	  private createWaTarget(waId: string, _messageId: string): RichMessageTarget {
520	    return {
521	      platform: "whatsapp",
522	      userId: waId,
523	      channelId: waId,
524	
525	      send: async (text: string): Promise<SentMessage> => {
526	        return this.sendWhatsAppText(waId, text);
527	      },
528	
529	      sendEphemeral: async (text: string): Promise<SentMessage> => {
530	        // WhatsApp has no ephemeral concept — send normally
531	        return this.sendWhatsAppText(waId, text);
532	      },
533	
534	      sendRich: async (richMsg: RichMessage): Promise<SentMessage> => {
535	        const markdown = richMessageToMarkdown(richMsg, "whatsapp");
536	        const text = convertToWhatsAppMarkdown(markdown);
537	        return this.sendWhatsAppText(waId, text);
538	      },
539	
540	      startTyping: async () => {
541	        // Typing indicator is already shown (and refreshed every 20s) by
542	        // handleIncomingMessage for the full duration of processing.
543	        // No second interval needed here.
544	        return () => undefined;
545	      },
546	    };
547	  }
548	
549	  // ---------------------------------------------------------------------------
550	  // Internal send helper
551	  // ---------------------------------------------------------------------------
552	
553	  /**
554	   * Sends a text message to a WhatsApp user via the Kapso SDK.
555	   *
556	   * Returns a {@link SentMessage} whose `edit` function sends a NEW message
557	   * (WhatsApp does not support editing existing messages).
558	   */
559	  private async sendWhatsAppText(
560	    waId: string,
561	    text: string,
562	  ): Promise<SentMessage> {
563	    const response = await this.whatsAppClient.messages.sendText({
564	      phoneNumberId: this.whatsAppConfig.kapsoPhoneNumberId,
565	      to: `+${waId}`,
566	      body: text,
567	    });
568	
569	    const messageId = response.messages[0]?.id ?? "";
570	
571	    return {
572	      id: messageId,
573	      edit: async (updatedText: string): Promise<void> => {
574	        // WhatsApp does not support message editing — send a new message instead
575	        await this.whatsAppClient.messages.sendText({
576	          phoneNumberId: this.whatsAppConfig.kapsoPhoneNumberId,
577	          to: `+${waId}`,
578	          body: updatedText,
579	        });
