1	/**
2	 * Shared streaming chat handler for all bot platforms.
3	 *
4	 * This module eliminates ~250 lines of duplicated streaming logic across
5	 * Discord, Slack, Telegram, and WhatsApp bots. Each bot provides thin callbacks:
6	 *
7	 *   editMessage   - Update the "Thinking..." message with new content
8	 *   onAuthError   - Show auth URL when user isn't linked
9	 *   onGenericError - Show formatted error message
10	 *
11	 * The shared function handles: text accumulation, throttled message edits
12	 * (to respect platform rate limits), cursor indicator display, timer
13	 * cleanup, and error routing through formatBotError.
14	 *
15	 * Usage in a bot command file:
16	 *   import { handleStreamingChat, STREAMING_DEFAULTS } from "@gaia/shared";
17	 *
18	 *   await handleStreamingChat(gaia, request, editMessage, onAuth, onErr,
19	 *     STREAMING_DEFAULTS.discord);
20	 */
21	import type { Analytics } from "../../analytics";
22	import { BOT_EVENTS } from "../../analytics/events/bots";
23	import type { GaiaClient } from "../api";
24	import type { ChatRequest } from "../types";
25	import { formatBotError } from "./formatters";
26	import { truncateResponse } from "./index";
27	
28	export interface StreamingOptions {
29	  editIntervalMs: number;
30	  streaming: boolean;
31	  platform: "discord" | "slack" | "telegram" | "whatsapp";
32	}
33	
34	export type MessageEditor = (text: string) => Promise<void>;
35	export type NewMessageSender = (text: string) => Promise<MessageEditor>;
36	
37	export const STREAMING_DEFAULTS: Record<
38	  "discord" | "slack" | "telegram" | "whatsapp",
39	  StreamingOptions
40	> = {
41	  discord: {
42	    editIntervalMs: 1200,
43	    streaming: false,
44	    platform: "discord",
45	  },
46	  slack: {
47	    editIntervalMs: 1500,
48	    streaming: true,
49	    platform: "slack",
50	  },
51	  telegram: {
52	    editIntervalMs: 1000,
53	    streaming: true,
54	    platform: "telegram",
55	  },
56	  whatsapp: {
57	    editIntervalMs: 2000,
58	    streaming: false,
59	    platform: "whatsapp",
60	  },
61	};
62	
63	/**
64	 * Internal streaming handler used by both authenticated and mention flows.
65	 */
66	async function _handleStream(
67	  streamFn: (
68	    onChunk: (text: string) => void | Promise<void>,
69	    onDone: (fullText: string, conversationId: string) => void | Promise<void>,
70	    onError: (error: Error) => void | Promise<void>,
71	  ) => Promise<string>,
72	  request: ChatRequest,
73	  gaia: GaiaClient,
74	  editMessage: MessageEditor,
75	  sendNewMessage: NewMessageSender | null,
76	  onAuthError: ((authUrl: string) => Promise<void>) | null,
77	  onGenericError: (formattedError: string) => Promise<void>,
78	  options: StreamingOptions,
79	): Promise<void> {
80	  const { editIntervalMs, streaming, platform } = options;
81	
82	  let lastEditTime = 0;
83	  let editTimer: ReturnType<typeof setTimeout> | null = null;
84	  let fullText = "";
85	  let streamDone = false;
86	  let currentEditor = editMessage;
87	  let sentText = "";
88	  let breakHandledDuringStreaming = false;
89	
90	  // Serialization queue to prevent concurrent Telegram API calls
91	  // which cause out-of-order message updates
92	  let opQueue: Promise<void> = Promise.resolve();
93	  const enqueue = (fn: () => Promise<void>): Promise<void> => {
94	    opQueue = opQueue.then(fn, fn);
95	    return opQueue;
96	  };
97	
98	  const updateDisplay = async (text: string) => {
99	    // Strip any unprocessed break tags before displaying
100	    const cleaned = text.replaceAll("<NEW_MESSAGE_BREAK>", "").trim();
101	    if (!cleaned) return;
102	    const truncated = truncateResponse(cleaned, platform);
103	    if (truncated === sentText) return;
104	    try {
105	      await currentEditor(truncated);
106	      sentText = truncated;
107	    } catch {
108	      // Message may have been deleted or interaction expired
109	    }
110	  };
111	
112	  const handleNewMessageBreak = async () => {
113	    if (!sendNewMessage) return;
114	
115	    while (fullText.includes("<NEW_MESSAGE_BREAK>")) {
116	      const breakIndex = fullText.indexOf("<NEW_MESSAGE_BREAK>");
117	      const beforeBreak = fullText.slice(0, breakIndex).trim();
118	      const afterBreak = fullText.slice(breakIndex + 19);
119	
120	      if (beforeBreak && beforeBreak !== sentText) {
121	        await updateDisplay(beforeBreak);
122	      }
123	
124	      const afterTrimmed = afterBreak.trim();
125	      if (!afterTrimmed) {
126	        // Break at end of text with nothing after — just update current segment
127	        fullText = "";
128	        breakHandledDuringStreaming = true;
129	        return;
130	      }
131	
132	      currentEditor = await sendNewMessage(
133	        afterTrimmed.replaceAll("<NEW_MESSAGE_BREAK>", "").trim() || "...",
134	      );
135	      fullText = afterTrimmed;
136	      sentText =
