  finalText.includes("<NEW_MESSAGE_BREAK>")
) {
  // Handle NEW_MESSAGE_BREAK for non-streaming platforms (e.g. Discord)
  fullText = finalText;
  sentText = "";
  const parts = fullText
    .split("<NEW_MESSAGE_BREAK>")
    .map((p) => p.trim())
    .filter(Boolean);
  if (parts.length > 0) {
    await updateDisplay(parts[0]);
    for (let i = 1; i < parts.length; i++) {
      currentEditor = await sendNewMessage(parts[i]);
    }
  }
} else {
  // For streaming, don't reset sentText — avoid re-sending already displayed content
  if (!streaming) {
    fullText = finalText;
    sentText = "";
  }

  // If the final text exceeds the platform limit and we can post
  // additional bubbles, deliver it as multiple chunks instead of
  // truncating with "... (truncated)". This keeps full content visible
  // on platforms like WhatsApp where we own a sendNewMessage callback.
  const cleanedFinal = fullText
    .replaceAll("<NEW_MESSAGE_BREAK>", "")
    .trim();
  if (
    sendNewMessage &&
    cleanedFinal.length > PLATFORM_LIMITS[platform]
  ) {
    const chunks = chunkResponse(cleanedFinal, platform);
    if (chunks.length > 0) {
      try {
        await currentEditor(chunks[0]);
        sentText = chunks[0];
      } catch {
        // First bubble may have been deleted or unavailable
      }
      for (let i = 1; i < chunks.length; i++) {
        currentEditor = await sendNewMessage(chunks[i]);
        sentText = chunks[i];
      }
    }
  } else {
    await updateDisplay(fullText);
  }
}

