  `every bubble ≤ ${LIMIT} chars`,
);
ok(
  t1.every((b) => (b.match(/```/g)?.length ?? 0) % 2 === 0),
  "every bubble has balanced code fences",
);
const everyLinkIntact =
  !t1.some((b) =>
    /\[[^\]]*$/.test(b) || /^\([^)]*$/.test(b),
  );
ok(everyLinkIntact, "no bubble ends mid-link or starts mid-URL");

// ─── Test 2: model emits NEW_MESSAGE_BREAK between ack + content ────────────
section("Test 2: ack + NEW_MESSAGE_BREAK + long list");

const ackThenList = [
  "bet aryan, pulling that for u rn",
  NEW_MESSAGE_BREAK_TOKEN,
  "yo here's the top 30 from hn:\n\n" +
    Array.from({ length: 30 }, (_, i) =>
      `• ${1500 - i * 17} pts | A really really really long story title that goes on and on about something interesting in the tech world today (${i + 1})`,
    ).join("\n"),
  NEW_MESSAGE_BREAK_TOKEN,
  "anything catch your eye?",
].join("\n");

console.log(`  source length: ${ackThenList.length} chars`);
const t2 = simulateDelivery(ackThenList, "whatsapp");
console.log(`  bubbles: ${t2.length}, sizes: ${t2.map((b) => b.length).join(",")}`);
ok(t2.length >= 3, `at least 3 bubbles (ack + list + question)`);
ok(t2[0] === "bet aryan, pulling that for u rn", "first bubble is the ack");
ok(t2.at(-1) === "anything catch your eye?", "last bubble is the follow-up question");
ok(
  t2.every((b) => b.length <= LIMIT),
  "every bubble fits the limit",
);

// ─── Test 3: 30k-char dump (skill output worst case) ────────────────────────
section("Test 3: 30,000-char skill output (single segment)");

const huge = Array.from({ length: 200 }, (_, i) =>
  `## Section ${i + 1}\n\n${"This is body text for the section. ".repeat(20)}`,
).join("\n\n");

console.log(`  source length: ${huge.length} chars`);
const t3 = simulateDelivery(huge, "whatsapp");
console.log(`  bubbles: ${t3.length}, sizes (first 3): ${t3.slice(0, 3).map((b) => b.length).join(",")}`);
ok(
  t3.every((b) => b.length <= LIMIT),
  `every bubble ≤ ${LIMIT}`,
);
ok(
  t3.length >= Math.ceil(huge.length / LIMIT),
  `bubble count covers the source (${t3.length} ≥ ${Math.ceil(huge.length / LIMIT)})`,
);
const reconstruct = t3.join("\n\n").replace(/\s+/g, " ");
const original = huge.replace(/\s+/g, " ");
ok(
  reconstruct.length >= original.length * 0.99,
  `≥99% of source length preserved (recon=${reconstruct.length}, src=${original.length})`,
);

// ─── Test 4: code-only response (model dumps a long python file) ────────────
section("Test 4: long fenced code block");

const codeBody = [
  "Here's the full module:",
  "",
  "```python",
  Array.from({ length: 200 }, (_, i) =>
    `def function_number_${i}(x: int, y: int) -> int:\n    """Doc for function ${i}."""\n    return x + y + ${i}`,
  ).join("\n\n"),
  "```",
  "",
  "lemme know if u want me to walk through any of it",
].join("\n");

console.log(`  source length: ${codeBody.length} chars`);
const t4 = simulateDelivery(codeBody, "whatsapp");
console.log(`  bubbles: ${t4.length}, fence counts: ${t4.map((b) => b.match(/```/g)?.length ?? 0).join(",")}`);
ok(
  t4.every((b) => b.length <= LIMIT),
  "every bubble fits",
);
ok(
  t4.every((b) => (b.match(/```/g)?.length ?? 0) % 2 === 0),
  "every bubble has balanced code fences (no orphan ```)",
);

// ─── Test 5: NEW_MESSAGE_BREAK with a segment > limit ───────────────────────
section("Test 5: break + segment > limit");

const breakOverflow = [
  "ok here u go",
  NEW_MESSAGE_BREAK_TOKEN,
  "a".repeat(8000),
  NEW_MESSAGE_BREAK_TOKEN,
  "let me know what u think",
].join("\n");

const t5 = simulateDelivery(breakOverflow, "whatsapp");
console.log(`  bubbles: ${t5.length}, sizes: ${t5.map((b) => b.length).join(",")}`);
ok(
  t5[0] === "ok here u go",
  "first bubble preserved as ack",
);
ok(
  t5.at(-1) === "let me know what u think",
  "last bubble preserved as follow-up",
);
ok(
  t5.every((b) => b.length <= LIMIT),
  "all bubbles fit",
);
ok(
  t5.length >= 4,
  `at least 4 bubbles (ack + 8000-char split + follow-up), got ${t5.length}`,
);

// ─── Test 6: link right at the boundary ─────────────────────────────────────
section("Test 6: markdown link straddling cut");

const linkAtBoundary =
  "x".repeat(LIMIT - 30) +
  " [some really long label](https://example.com/very/long/url/path/that/goes/on) trailing text";
const t6 = simulateDelivery(linkAtBoundary, "whatsapp");
console.log(`  bubbles: ${t6.length}, sizes: ${t6.map((b) => b.length).join(",")}`);
ok(
  t6.some((b) =>
    b.includes("[some really long label](https://example.com/very/long/url/path/that/goes/on)"),
  ),
  "link kept intact in exactly one bubble",
);

// ─── Test 7: typical short reply (regression) ───────────────────────────────
section("Test 7: typical short conversational reply");

const short = "heyyy not much, what's good?";
const t7 = simulateDelivery(short, "whatsapp");
ok(t7.length === 1 && t7[0] === short, "short reply is one bubble unchanged");

// ─── Test 8: short reply with one break ─────────────────────────────────────
section("Test 8: short reply with one break");

const shortWithBreak = `bet${NEW_MESSAGE_BREAK_TOKEN}lemme check that for u`;
const t8 = simulateDelivery(shortWithBreak, "whatsapp");
ok(
  t8.length === 2 && t8[0] === "bet" && t8[1] === "lemme check that for u",
  `two bubbles (got ${t8.length}: ${JSON.stringify(t8)})`,
);

// ─── Summary ────────────────────────────────────────────────────────────────
console.log(`\n${pass}/${pass + fail} assertions passed`);
process.exit(fail === 0 ? 0 : 1);

