import {
  chunkResponse,
  PLATFORM_LIMITS,
} from "./libs/shared/ts/src/bots/utils/index.ts";

const ok = (cond: boolean, msg: string) =>
  console.log((cond ? "✓" : "✗") + " " + msg);

const r1 = chunkResponse("hello world", "whatsapp");
ok(r1.length === 1 && r1[0] === "hello world", "short text returns single chunk");

const long =
  "a".repeat(5000) + "\n\n" + "b".repeat(5000) + "\n\n" + "c".repeat(2000);
const r2 = chunkResponse(long, "whatsapp");
ok(
  r2.every((c) => c.length <= PLATFORM_LIMITS.whatsapp),
  `${r2.length} chunks all ≤ 4096 (sizes: ${r2.map((c) => c.length).join(",")})`,
);
ok(
  r2.join("").replace(/\s/g, "") === long.replace(/\s/g, ""),
  "all content preserved",
);

const linkBody =
  "x".repeat(4080) +
  " [a label](https://example.com/some/long/url) trailing";
const r3 = chunkResponse(linkBody, "whatsapp");
const intactInOne = r3.some((c) =>
  c.includes("[a label](https://example.com/some/long/url)"),
);
ok(intactInOne, `link kept intact in one chunk (chunks: ${r3.length})`);

const fenceBody =
  "y".repeat(4080) + "\n```python\nprint('hi')\n```\nplain after";
const r4 = chunkResponse(fenceBody, "whatsapp");
const balanced = r4.every(
  (c) => (c.match(/```/g)?.length ?? 0) % 2 === 0,
);
ok(
  balanced,
  `every chunk has even number of fences (counts: ${r4
    .map((c) => c.match(/```/g)?.length ?? 0)
    .join(",")})`,
);

const tightFence =
  "```python\n" + "z".repeat(4070) + "\n```\nfollowing text";
const r5 = chunkResponse(tightFence, "whatsapp");
const r5Balanced = r5.every(
  (c) => (c.match(/```/g)?.length ?? 0) % 2 === 0,
);
ok(
  r5Balanced,
  `tight-fence: balanced (counts: ${r5
    .map((c) => c.match(/```/g)?.length ?? 0)
    .join(",")}, sizes: ${r5.map((c) => c.length).join(",")})`,
);
console.log("  chunk 5[0] tail:", JSON.stringify(r5[0].slice(-40)));
console.log("  chunk 5[1] head:", JSON.stringify(r5[1]?.slice(0, 40) ?? ""));

const hugeLink = "[label](" + "u".repeat(5000) + ")";
const r6 = chunkResponse(hugeLink, "whatsapp");
ok(
  r6.every((c) => c.length <= PLATFORM_LIMITS.whatsapp),
  `huge link chunked, sizes: ${r6.map((c) => c.length).join(",")}`,
);

const exact = "a".repeat(4096);
const r7 = chunkResponse(exact, "whatsapp");
ok(
  r7.length === 1 && r7[0].length === 4096,
  "exact-limit returns single chunk",
);

const justOver = "a".repeat(4097);
const r8 = chunkResponse(justOver, "whatsapp");
ok(
  r8.length === 2 && r8.every((c) => c.length <= PLATFORM_LIMITS.whatsapp),
  `4097 → ${r8.length} chunks (sizes: ${r8.map((c) => c.length).join(",")})`,
);

