/**
 * Returns true if cutting ``text`` at index ``idx`` would land inside an
 * unclosed markdown emphasis span (``**bold**``, ``*italic*``, ``_underline_``,
 * ``~strike~``, `` `code` ``). Catches the case where the prefix has an odd
 * number of a given marker and a matching closer exists later in the text —
 * meaning the cut would orphan one half of the pair as stray punctuation
 * (e.g. ``"foo **bol"`` plus ``"d** bar"`` shows literal ``**`` to the user).
 *
 * ``**`` is checked before ``*`` so a balanced ``**X**`` isn't misread as
 * three separate ``*`` markers.
 */
function cutsInsideEmphasisSpan(text: string, idx: number): boolean {
  const prefix = text.slice(0, idx);
  const suffix = text.slice(idx);

  // Order matters: longest markers first so `**` doesn't double-count as `*`.
  const markers: { open: RegExp; raw: string }[] = [
    { open: /\*\*/g, raw: "**" },
    { open: /\*/g, raw: "*" },
    { open: /_/g, raw: "_" },
    { open: /~/g, raw: "~" },
    { open: /`/g, raw: "`" },
  ];

  // Strip ``**`` matches from the prefix before counting bare ``*`` so a
  // balanced ``**X**`` doesn't register as three single-asterisk markers.
  let prefixForSingle = prefix;
  let suffixForSingle = suffix;

  for (const { open, raw } of markers) {
    const target = raw === "*" ? prefixForSingle : prefix;
    const targetSuffix = raw === "*" ? suffixForSingle : suffix;
    const opens = (target.match(open) ?? []).length;
    if (opens % 2 === 1 && targetSuffix.includes(raw)) return true;
    if (raw === "**") {
      prefixForSingle = prefixForSingle.replaceAll("**", "");
      suffixForSingle = suffixForSingle.replaceAll("**", "");
    }
  }
  return false;
}

