 * ``**`` somewhere in the suffix means the cut would orphan one half of the
 * pair. Same logic for backticks (excluding triple-backticks, which are
 * handled separately by the fence-balancing step in {@link chunkResponse}).
 */
function cutsInsideEmphasisSpan(text: string, idx: number): boolean {
  const prefix = text.slice(0, idx);
  const suffix = text.slice(idx);

  const doubleAsteriskOpens = (prefix.match(/\*\*/g) ?? []).length;
  if (doubleAsteriskOpens % 2 === 1 && suffix.includes("**")) return true;

  // Inline backticks: count single backticks that are NOT part of a ``` fence.
  // Strip triple-backticks first so we only count inline-code markers.
  const prefixNoFence = prefix.replaceAll("```", "");
  const suffixNoFence = suffix.replaceAll("```", "");
  const inlineTickOpens = (prefixNoFence.match(/`/g) ?? []).length;
  if (inlineTickOpens % 2 === 1 && suffixNoFence.includes("`")) return true;

  return false;
}

