async () => {
  const box = document.querySelector('div[contenteditable="true"][role="textbox"]');
  if (!box) return { error: "no textbox" };

  box.focus();
  box.click();

  // Insert text using the Selection + InputEvent API used by WhatsApp Web
  document.execCommand('insertText', false, 'hi');

  // Wait a tick for WhatsApp's React state to register the input
  await new Promise(r => setTimeout(r, 300));

  // Find the send button by aria-label
  const sendBtn = document.querySelector('button[aria-label="Send"]')
    || document.querySelector('span[data-icon="send"]')?.closest('button')
    || document.querySelector('div[role="button"][aria-label="Send"]');

  if (!sendBtn) {
    // Fall back to firing an Enter key event
    const evt = new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true });
    box.dispatchEvent(evt);
    return { sent: 'enter-key', text: box.innerText };
  }

  sendBtn.click();
  return { sent: 'click', text: box.innerText };
}

async () => {
  const box = document.querySelector('div[contenteditable="true"][role="textbox"]');
  if (!box) return { error: 'no textbox' };
  box.focus();

  // Build a synthetic clipboard event WhatsApp Web's React handler accepts
  const dt = new DataTransfer();
  dt.setData('text/plain', 'hi');
  const evt = new ClipboardEvent('paste', {
    clipboardData: dt,
    bubbles: true,
    cancelable: true,
  });
  box.dispatchEvent(evt);
  await new Promise(r => setTimeout(r, 400));
  return { textNow: box.innerText, html: box.innerHTML.slice(0, 200) };
}

async () => {
  const box = document.querySelector('div[contenteditable="true"][role="textbox"]');
  // Press Enter — WhatsApp's input registers it via Lexical
  ['keydown', 'keypress', 'keyup'].forEach(type => {
    box.dispatchEvent(new KeyboardEvent(type, {
      key: 'Enter', code: 'Enter', keyCode: 13, which: 13,
      bubbles: true, cancelable: true,
    }));
  });
  await new Promise(r => setTimeout(r, 600));
  return { textAfterSend: box.innerText, len: box.innerText.length };
}

