() => {
  const containers = document.querySelectorAll('[class*="message-in"], [class*="message-out"]');
  const msgs = [];
  containers.forEach(c => {
    const txt = c.innerText;
    if (txt && txt.trim()) msgs.push({
      isOut: c.className.includes('message-out'),
      len: txt.length,
      head: txt.slice(0, 100),
      tail: txt.slice(-100),
    });
  });
  return { total: msgs.length, last4: msgs.slice(-4) };
}

async () => {
  // Click any "Read more" button to expand collapsed messages
  const btns = [...document.querySelectorAll('div[role="button"]')].filter(b =>
    b.innerText && b.innerText.trim() === 'Read more'
  );
  for (const b of btns) { b.click(); await new Promise(r => setTimeout(r, 200)); }
  return { expanded: btns.length };
}

() => {
  const containers = document.querySelectorAll('[class*="message-in"], [class*="message-out"]');
  const msgs = [];
  containers.forEach(c => {
    const txt = c.innerText;
    if (txt && txt.trim()) msgs.push({ isOut: c.className.includes('message-out'), len: txt.length, text: txt });
  });
  return { total: msgs.length, last3: msgs.slice(-3).map(m => ({ isOut: m.isOut, len: m.len, head: m.text.slice(0, 200), tail: m.text.slice(-200) })) };
}

