async () => {
  const box = document.querySelector('div[contenteditable="true"][role="textbox"]');
  box.focus();
  const dt = new DataTransfer();
  dt.setData('text/plain', 'give me an extremely long markdown reference doc with bold headings, multiple bullet lists, several fenced code blocks (python and bash), and a couple of inline links — go big, like 8000 characters');
  box.dispatchEvent(new ClipboardEvent('paste', { clipboardData: dt, bubbles: true, cancelable: true }));
  await new Promise(r => setTimeout(r, 300));
  ['keydown', 'keypress', 'keyup'].forEach(type => {
    box.dispatchEvent(new KeyboardEvent(type, { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true, cancelable: true }));
  });
  await new Promise(r => setTimeout(r, 400));
  return { textNow: box.innerText, sent: box.innerText.length <= 2 };
}

