async () => {
  // Expand any "Read more" buttons
  const btns = [...document.querySelectorAll('div[role="button"]')].filter(b =>
    b.innerText && b.innerText.trim() === 'Read more'
  );
  for (const b of btns) { b.click(); await new Promise(r => setTimeout(r, 200)); }

  const containers = document.querySelectorAll('[class*="message-in"], [class*="message-out"]');
  const msgs = [];
  containers.forEach(c => {
    const txt = c.innerText;
    if (txt && txt.trim()) msgs.push({ isOut: c.className.includes('message-out'), text: txt });
  });
  // Return only the most recent inbound bubbles after my latest outbound
  let lastOutIdx = -1;
  msgs.forEach((m, i) => { if (m.isOut) lastOutIdx = i; });
  const newInbound = msgs.slice(lastOutIdx + 1);
  return {
    expanded: btns.length,
    totalMsgs: msgs.length,
    newBubbles: newInbound.map(m => ({
      len: m.text.length,
      head: m.text.slice(0, 200),
      tail: m.text.slice(-200),
    })),
  };
}

