// Belt-and-suspenders: balance unbalanced ``**`` markers across the cut.
// If a single ``**`` is orphaned on either side of the boundary, strip it
// so convertToWhatsAppMarkdown's pair regex does not greedily merge it
// with the next ``**`` of an unrelated emphasis span and produce
// ``Stack*: ... *Jaeger`` -style stray asterisks.
const chunkOpens = (chunk.match(/\*\*/g) ?? []).length;
if (chunkOpens % 2 === 1) {
  const lastIdx = chunk.lastIndexOf("**");
  chunk = chunk.slice(0, lastIdx) + chunk.slice(lastIdx + 2);
  const firstIdx = next.indexOf("**");
  if (firstIdx !== -1) {
    next = next.slice(0, firstIdx) + next.slice(firstIdx + 2);
  }
}

