  const stats = msgs.map(t => ({
    hasTruncMarker: /\(truncated\)|\.\.\. \(truncated\)/.test(t),
    hasDoubleAsterisks: /\*\*/.test(t),
    hasOrphanAsterisk: / \*[^\s].*?[^\s\*]\*[ \n]|\*[A-Za-z]/.test(t) && !/\*[A-Za-z][^\*\n]+\*/.test(t),
    sample: t.slice(0, 80),
  }));
  return { count: stats.length, stats: stats.slice(-4) };
}

async () => {
  const containers = document.querySelectorAll('[class*="message-in"]');
  const target = containers[containers.length - 2]; // 2nd-to-last inbound
