238	 * @param platform - The target platform (discord, slack, telegram, whatsapp).
239	 * @returns An array of chunks, in order, each ≤ the platform character limit.
240	 *   Returns ``[text]`` when ``text`` already fits.
241	 */
242	export function chunkResponse(
243	  text: string,
244	  platform: "discord" | "slack" | "telegram" | "whatsapp",
245	): string[] {
246	  const limit = PLATFORM_LIMITS[platform];
247	  if (text.length <= limit) return [text];
248	
249	  // Reserve space for code-fence balancing markers ("\n```" + "```\n") so a
250	  // chunk that closes/reopens a fence still fits inside the platform limit.
251	  const FENCE_HEADROOM = 8;
252	  const cutLimit = limit - FENCE_HEADROOM;
253	
254	  const chunks: string[] = [];
255	  let remaining = text;
