async () => {
  const btns = [...document.querySelectorAll('div[role="button"]')].filter(b => b.innerText && b.innerText.trim() === 'Read more');
  for (const b of btns) { b.click(); await new Promise(r => setTimeout(r, 200)); }
  const containers = document.querySelectorAll('[class*="message-in"], [class*="message-out"]');
  const msgs = [];
  containers.forEach(c => {
    const txt = c.innerText;
    if (txt && txt.trim()) msgs.push({ isOut: c.className.includes('message-out'), text: txt });
  });
  let lastOutIdx = -1;
  msgs.forEach((m, i) => { if (m.isOut) lastOutIdx = i; });
  return msgs.slice(lastOutIdx + 1).map(m => ({
    len: m.text.length,
    head: m.text.slice(0, 250),
    tail: m.text.slice(-250),
    hasTrunc: /\(truncated\)/.test(m.text),
    leadingWhitespaceLines: m.text.split('\n').slice(0, 6).map(l => ({ first8: JSON.stringify(l.slice(0, 8)) })),
  }));
}

