123	 * Returns true if cutting ``text`` at index ``idx`` would land inside an
124	 * unclosed markdown emphasis span. We only check the two markers that bite us
125	 * in practice: ``**bold**`` (model emits markdown bold even when output goes
126	 * to WhatsApp) and `` `inline code` ``. Single ``*``, ``_``, ``~`` are skipped
127	 * because they appear in code identifiers, URLs, and plain prose — the false
128	 * positive rate is too high to be worth the rare valid catch.
129	 *
130	 * The check is symmetric: an odd number of ``**`` in the prefix AND a closing
131	 * ``**`` somewhere in the suffix means the cut would orphan one half of the
132	 * pair. Same logic for backticks (excluding triple-backticks, which are
133	 * handled separately by the fence-balancing step in {@link chunkResponse}).
134	 */
135	function cutsInsideEmphasisSpan(text: string, idx: number): boolean {
136	  const prefix = text.slice(0, idx);
137	  const suffix = text.slice(idx);
138	
139	  // Strip fenced code blocks (``` ... ```) before counting markers — code can
140	  // legitimately contain ``**`` (e.g. Python ``**kwargs``) and stray
141	  // backticks (e.g. shell quoting), and those bytes must not poison the
142	  // emphasis parity check that's deciding cut positions in narrative text.
143	  const stripFences = (s: string): string => {
144	    let out = "";
145	    let inFence = false;
146	    let i = 0;
147	    while (i < s.length) {
148	      if (s.startsWith("```", i)) {
149	        inFence = !inFence;
150	        i += 3;
151	        continue;
152	      }
153	      if (!inFence) out += s[i];
154	      i++;
155	    }
156	    return out;
157	  };
158	  const prefixNarrative = stripFences(prefix);
159	  const suffixNarrative = stripFences(suffix);
160	
161	  const doubleAsteriskOpens = (prefixNarrative.match(/\*\*/g) ?? []).length;
162	  if (doubleAsteriskOpens % 2 === 1 && suffixNarrative.includes("**"))
163	    return true;
164	
165	  const inlineTickOpens = (prefixNarrative.match(/`/g) ?? []).length;
