1	import { createHmac, timingSafeEqual } from "node:crypto";
2	
3	/**
4	 * Verifies a Kapso webhook signature.
5	 *
6	 * Kapso signs the raw request body with HMAC-SHA256 using your webhook secret.
7	 * The signature is provided in the X-Webhook-Signature header as a raw hex string
8	 * (no prefix).
9	 */
10	export function verifyKapsoSignature(
11	  rawBody: string,
12	  signatureHeader: string | null,
13	  secret: string,
14	): boolean {
15	  if (!signatureHeader) return false;
16	  const expected = createHmac("sha256", secret)
17	    .update(rawBody, "utf8")
18	    .digest("hex");
19	  try {
20	    return timingSafeEqual(Buffer.from(signatureHeader), Buffer.from(expected));
21	  } catch {
22	    return false;
23	  }
24	}
25	
