private async sendWhatsAppText(
  waId: string,
  text: string,
): Promise<SentMessage> {
  // TEMP DEBUG — capture every outbound bubble verbatim so we can audit
  // chunk boundaries and asterisk parity from the log. Remove once the
  // markdown-aware chunking is confirmed working in production.
  this.adapterLogger.info("outbound_bubble_debug", {
    wa_hash: hashLogIdentifier(waId),
    length: text.length,
    head_120: text.slice(0, 120),
    tail_120: text.slice(-120),
    single_asterisk_count: (text.replaceAll("**", "").match(/\*/g) ?? [])
      .length,
    double_asterisk_count: (text.match(/\*\*/g) ?? []).length,
  });

  const response = await this.whatsAppClient.messages.sendText({
    phoneNumberId: this.whatsAppConfig.kapsoPhoneNumberId,
    to: `+${waId}`,
    body: text,
  });

  const messageId = response.messages[0]?.id ?? "";

